#!/usr/bin/env perl
use strict; use warnings;
use CGI qw(:standard);
require Scalar::Util 'blessed'; # for blessed function, used to check if a variable is scalar contextually (i.e., it's an object) or not 
my $log_dir = '/path/to/your/directory';  
# Define the directory where your log files are stored and make sure this path exists in advance!   
print header('text/html'); # Print headers for HTML content type. This is necessary to display any output as a web page 
my $filename= param('logfile') // die "No Log File Provided";  
# If no log file provided, then stop the script and print an error message (die).   
if(blessed($filename) && grep{/^$filename\z/} <qw(/proc /dev /sys $ENV{'HOME'})){  # Check if filename is a valid path. If yes:  
 die "Invalid Log File Path";     }     
open my $FH, '<', "$log_dir/$filename" or die "Could not open file for reading :  $!";   
# Open the logfile in read mode and check if it was successful (die otherwise). 
print start_html('Log Viewer'); # Print HTML content type headers. This is necessary to display any output as a web page  
my $content= do { local $/; <$FH> };    # Read the file into variable 'Content'. The last line of each block will be set in Content 
print "<pre>$content</pre>";     # Print content with HTML tags. This makes it easier to view log files on web browsers  
close $FH or die;                    # Close File Handle and check if successful (die otherwise).   
end_html();                         # End of the html block